require "event.BaseEvent"

TransferEvent = class("TransferEvent", BaseEvent)

function TransferEvent:onTriggered(player)
    if player:ifOnMount() then
        return
    end
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgTransfer())
    LuaTimer:schedule(function(playerId)
        local c_player = PlayerManager:getPlayerByUserId(playerId)
        if not c_player or c_player.isLife == false then
            return
        end
        if c_player:ifOnMount() then
            return
        end
        local curIsland = IslandConfig:inWhichIsland(c_player:getPosition())
        local pos = IslandConfig:randomPos(curIsland, 0)
        c_player:teleportPos(pos)
    end, 2000, nil, player.userId)
end

return TransferEvent